INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'L’Imâm Al-Halîmi explique le Nom de Allâh « Al-Mouta’âlî » (rapporté par Al-Bayhaqi)', 'Halimi', 'معناه : المرتفع عن أن يجوز عليه ما يجوز على المحدَثين من الأزواج والأولاد والجوارح والأعضاء واتخاذ السرير للجلوس عليه، والاحتجاب بالستور عن أن تنفذ الأبصار إليه، والانتقال من مكان إلى مكان ونحو ذلك، فإن إثبات بعض هذه الأشياء يوجب النهاية، وبعضها يوجب الحاجة، وبعضها يوجب التغير والاستحالة، وشىء من ذلك غير لائق بالقديم ولا جائز عليه', '« Cela signifie qu’Il est exempt du fait que Lui soit possible ce qui est possible aux choses qui entrent en existence : le mariage, l’enfantement, les organes et les membres et le fait de prendre un lit pour s’asseoir dessus, de se préserver de l’atteinte des regards avec un paravent, le déplacement d’un endroit à un autre et ce qui est semblable. En effet, la confirmation de certaines de ces choses impose l’extrémité, certaines imposent le besoin et d’autres imposent le changement et le passage d’un état à un autre. Et rien de tout ceci ne convient à la dignité de Al-Qadîm (Celui Qui n’a pas de début à son existence) et cela n’est pas possible à Son sujet ».', '', 'Dans son livre « Al-Asmâ-ou wa s-Sifât » (page 47 de cette édition), l’Imâm Al-Bayhaqi rapporte que l’Imâm Al-Halîmi a dit au sujet du nom de Allâh « Al-Mouta’âlî » :
Informations utiles :
– L’Imâm, le Hâfidh Aboû Bakr Ahmad Ibnou l-Houçayn Al-Bayhaqi, est né en 384 et il est décédé en 458 de l’hégire (رحمه الله), c’est-à-dire il y a presque 1000 ans. Il fait partie des plus grands savants du hadîth, et il est de l’école de jurisprudence Châfi’ite. Son livre « Al-Asmâ-ou wa s-Sifât » est un livre de référence sur la croyance, qui traite des Noms et des Attributs de Allah. Voir la biographie de l’Imâm Al-Bayhaqi : ici .
– L’Imâm, le Faqîh( spécialiste de la jurisprudence), le Qâdî (juge), Abou ‘Abdi l-Lâh Al-Houçayn Ibnou Al-Haçan Al-Halîmi Al-Boukhâri Ach-Châfi’i est né en 338 et il est décédé en 403 de l’Hégire à Boukhârâ (رحمه الله) c’est-à-dire il y a environ de 1030 ans. C’est un grand savant dans l’école de jurisprudence (madh-hab) de l’Imâm Ach-Châfi’i, dans lequel il a le niveau de Moujtahid mouqayyad. Il est également très connu dans la science du hadîth. L’Imâm Al-Bayhaqi le cite énormément dans son livre « Al-Asmâ-ou wa s-Sifât ».
– Ici, il dit clairement que Allâh est exempt des organes, des membres, du fait de s’asseoir, du déplacement, ainsi que du changement.', 'al asma wa sifat, al-asma’ou wa s-sifat, al-bayhaqi, al-halimi'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = 'معناه : المرتفع عن أن يجوز عليه ما يجوز على المحدَثين من الأزواج والأولاد والجوارح والأعضاء واتخاذ السرير للجلوس عليه، والاحتجاب بالستور عن أن تنفذ الأبصار إليه، والانتقال من مكان إلى مكان ونحو ذلك، فإن إثبات بعض هذه الأشياء يوجب النهاية، وبعضها يوجب الحاجة، وبعضها يوجب التغير والاستحالة، وشىء من ذلك غير لائق بالقديم ولا جائز عليه');

