INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'Le Chaykh Yahyâ Ibn Mou’âdh (du salaf) répond à quelqu’un qui lui demande « où est Allâh ? »', 'Yahya Ibn Mou''adh', 'وقيل ليحيى بن معاذ (الرازي) : أَخْبِرْني عن الله عز وجل ، فقال : إله واحد ، فقيل له : كيف هو ؟ قال : ملك قادر ، فقيل : أين هو ؟ فقال : هو بالمرصاد ، فقال السائل : لم أسألك عن هذا ؟ فقال : ما كان غير هذا كان صفة المخلوق ، فأما صفته فما أخبرتك عنها .', '« Quelqu’un demanda à Yahyâ ibn Mou’âdh (Ar-Râzi) : « Parle-moi de Allâh ‘azza wa jall »', '', 'Dans sa célèbre Epître « Ar-Riçâlatou l-Qouchayriyyah » (page 12 de cette édition) l’Imâm Al-Qouchayri a dit :
Yahyâ ibn Mou’âdh répondit : « Il est un Dieu unique. »
On lui demanda : « Comment est-Il ? »
Yahyâ répondit : « Un Seigneur tout-puissant. »
On lui dit ensuite : « Où est-Il ? »
Yahyâ répondit [par une phrase qui signifie]: « Il voit et Il entend (houwa bi l-Mirsâd) »
La personne qui l’interrogeait objecta : « Ma question ne porte pas sur cela ! »
Alors Yahyâ lui dit : « Ce qui est autre que cela est un attribut de la créature. Quant à Ses attributs, ils sont tels que je viens de te les citer. » »
Informations utiles :
– Le Chaykh Aboû Zakariyyâ Yahyâ ibn Mou’âdh ibn Ja’far Ar-Râzi est un savant du salaf, il est décédé en 258 de l’Hégire (رحمه الله) c’est-à-dire il y a environ 1175 ans.
– Ici lorsque quelqu’un lui demande « où est Allâh ? », il lui fait comprendre qu’on ne pose pas cette question au sujet du Créateur (c’est-à-dire au sujet de Allâh) mais que cette question se pose uniquement au sujet des créatures.
– Cette citation de Yahyâ Ibnou Mou’âdh Ar-Râzi a également été rapportée par l’Imâm Ibnou ‘Abdi s-Salâm dans son livre Hallou r-Roumoûz.
– Les savants de l’Islâm ont dit qu’il est interdit de dire « où ? » au sujet de Allâh, car Il est Le Créateur de l’endroit. Retrouvez d’autres articles à ce sujet : ici .
– Le Mouhaddith–transmetteurs du hadîth–, le Moufassir –exégète–, le Chaykh Abou l-Qâçim Abdou l-Karîm ibnou Houwâzin al-Qouchayri est né en 375 et il est décédé en 465 de l’Hégire (رحمه الله) c’est-à-dire il y a environ 970 ans. Son livre « Ar-Riçâlatou l-Qouchayriyyah » est son ouvrage le plus connu. La première partie de ce livre est consacrée à la croyance de Ahlou s-Sounnah wa-l Jamâ’ah. On compte de parmi ses nombreux Chouyoûkh : l’Imâm Ibnou Foûrak, Aboû Is-hâq Al-Isfarâyîni, et le Hâfidh Al-Hâkim.
Tâjou d-Dîn As-Soubki a dit à son sujet : « L’Imâm absolu, l’auteur de “Ar-Riçâlah” qui s’est répandu de l’orient à l’occident […] l’un des Imâms des musulmans dans la science et les œuvres, une forteresse de la religion par ses actes et ses paroles, l’Imams des Imams […] le Chaykh des Mâchaykh […] il était Faqîh (spécialiste du fiqh), excellent, un Ousoûli (spécialiste des fondements), précautionneux, un Moutakallim (spécialiste de la science de la croyance), un Mouhaddith (transmetteur du hadîth), un Hâfidh (spécialiste de la science du hadîth), un Moufassir (spécialiste de l’explication du Qour-ân), il était versé dans les diverses sciences, un Nahwi (spécialiste de la grammaire), un Loughawi (spécialiste de la langue Arabe) […] les gens de son époque sont unanimes qu’il est le maître (sayyid) de son temps, le modèle (qoudwah) de son époque, et une bénédiction pour les musulmans dans son époque » [Tabaqâtou ch-Châfi’iyyah Al-Koubrâ]
Ibn Khallikân a dit à son sujet : « Abou l-Qâçim était un illustre savant (‘allâmah) dans le fiqh (jurisprudence), le tafsîr (explication du Qour-ân), le hadîth, al-Ousoûl (les fondements de la religion) » [Wafayâtou l-A’yân]
Adh-Dhahabi a dit de lui : « L’Imâm, l’ascète, le modèle (Qoudwah)» [Siyar A’lâmi n-Noubalâ]
– Al-Bayhaqi a rapporté que le compagnon Ibn ‘Abbâs (رضي الله عنه) a interprété la parole de Allâh « إن ربك لبالمرصاد » (Inna Rabbaka labi l-mirsâd) par le fait que Allâh entend et voit.', 'al-qouchayri, allah, aqida, ar-razi'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = 'وقيل ليحيى بن معاذ (الرازي) : أَخْبِرْني عن الله عز وجل ، فقال : إله واحد ، فقيل له : كيف هو ؟ قال : ملك قادر ، فقيل : أين هو ؟ فقال : هو بالمرصاد ، فقال السائل : لم أسألك عن هذا ؟ فقال : ما كان غير هذا كان صفة المخلوق ، فأما صفته فما أخبرتك عنها .');

-- source: https://islamsunnite.net/limam-ach-chahrastani-parle-de-la-mauvaise-comprehension-des-anthropomorphistes/
INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'L’Imâm Ach-Chahrastâni parle de la mauvaise compréhension des corporalistes', 'Les Chafi''ites', 'وأما ما ورد في التنزيل من الاستواء والوجه واليدين والجنب والمجيء والإتيان والفوقية وغير ذلك فأجروها على ظاهرها أعني ما يفهم عند الإطلاق على الأجسام', '« En ce qui concerne les expressions révélées (c’est-à-dire présentes dans le Qour-ân ou la Sounnah) telles que « al-istiwâ », « al-wajh », « al-yadayn », « al-janb », « al-majî », « al-ityân », « al-fawqiyyah » et d’autres que celles-ci, les corporalistes les prennent selon leur sens apparent, je veux dire telles qu’elles sont comprises lorsqu’elles sont employées au sujet des corps »', '', 'Dans son livre « Al-Milal wa n-Nihal » (page 69 de cette édition) qui traite des différentes sectes se réclamant de l’Islâm, l’Imâm Ach-Chahrastâni, dans le chapitre sur les mouchabbihah (corporalistes) a dit :
Informations utiles :
– Le Chaykh Mouhammad Ibnou ‘Abdou l-Karîm Ach-Chahrastâni est décédé en 548 de l’Hégire (رحمه الله) c’est-à-dire il y a plus de 880 ans. Il était du madh-hab (école de jurisprudence) de l’Imâm Ach-Châfi’i.
– Son livre « Al-Milal wa n-Nihal » traite des différentes religions et des différentes sectes se réclamant de l’Islam tel que les mou’tazilah, les jabriyyah, les khawârij, les mouchabbihah etc…
– Cette citation est tirée du chapitre qu’il a écrit concernant les mouchabbihah (corporalistes). Il dit que le fait de prendre les expressions citées selon le sens apparent est du corporalisme (tachbîh), c’est-à-dire le fait d’assimiler Allâh à Ses créatures.
– De nos jours, nous rencontrons également des corporalistes qui prennent ces expressions selon leur sens apparent, et qui les comprennent comme des parties corporelles, comme certains qui disent que Allâh a deux mains, un visage, qu’Il s’assoit , s’établit ou s’installe. na’oûdhoubi l-Lâh.
– En parcourant ce site vous trouverez des explications de savants au sujet des expressions comme « istiwâ », « wajh », « fawq » etc, lorsqu’elles sont employées au sujet de Allâh.', 'al milal wa n-nihal, allah, anthropomorphiste, aqida'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = 'وأما ما ورد في التنزيل من الاستواء والوجه واليدين والجنب والمجيء والإتيان والفوقية وغير ذلك فأجروها على ظاهرها أعني ما يفهم عند الإطلاق على الأجسام');

