INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'Le Hâfidh Ibn Hajar Al-‘Asqalâni dit que Allâh est sans endroit (rapporté par le Hâfidh As-Sakhâwi)', 'Sakhawi', 'قال شيخنا – يعني الحافظ ابن حجر العسقلاني – : إنَّ علـم الله يشمل جميع الأقطار ، والله سبحانه وتعالى منـزه عن الحلول في الأماكن ، فإنه سبحانه وتعالى كان قبل أن تحدث الأماكن', '« Notre Chaykh –il vise le Hâfidh Ibnou Hajar Al-‘Asqâlani– a dit : La science de Allâh concerne tous les endroits et Allâh soubhânahou wa ta’âlâ est exempt d’être incarné dans les endroits, en effet, Allâh soubhânahou wa ta’âlâ existe de toute éternité avant que les endroits n’entrent en existence ».', '', 'Dans son livre « Al-Maqâsidou l-Haçanah » (page 342 de cette édition) le Hâfidh As-Sakhâwi a dit :
Informations utiles :
– Le Hâfidh Chams ad-Dîn Mouhammad Ibnou ‘Abdi r-Rahmân As-Sakhâwi est né en 831 au Caire et il est décédé en 902 de l’Hégire à Médine (رحمه الله) c’est-à-dire il y a environ 530 ans. Il était un grand savant reconnu dans la science du hadîth et il était du madhab (école de jurisprudence) Chafi’ite. Il a eu de parmi ses Chaykh l’Imâm Ibnou Hajar Al-‘Asqalâni.
– Chaykhou l-Islâm, Amîr al-Mouminîn fi l-hadîth (le Prince des croyants dans la science du hadîth) Chihâb ad-Dîn Abou l-Fadl Ahmad Ibnou ‘Ali Ibnou Hajar Al-‘Asqalâni est né en 773 et il est décédé en 852 de l’hégire (رحمه الله) c’est-à-dire il y a plus de 590 ans. C’est un très grand spécialiste de la science du hadîth qui a écrit de nombreux ouvrages. Il est du madh-hab (Ecole de jurisprudence) de l’Imam Ach-Châfi’i. Son livre « Fath Al-Bârî » est incontournable, c’est le plus célèbre commentaire du Sahîh Al-Boukhâri. Consultez sa biographie : ici .
– Ici, il confirme la croyance du tawhîd, sur le fait que Allâh n’est pas dans un endroit.', '3asqalani, allah, aqida, asqalani'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = 'قال شيخنا – يعني الحافظ ابن حجر العسقلاني – : إنَّ علـم الله يشمل جميع الأقطار ، والله سبحانه وتعالى منـزه عن الحلول في الأماكن ، فإنه سبحانه وتعالى كان قبل أن تحدث الأماكن');

