SELECT 'Les sortes d’innovations.', 'Ibn ''Abdi s-Salam', '« البدعة بكسر الباء في الشرع هي: إحداث ما لم يكن في عهد رسول الله صلّى الله عليه وءاله وسلم، وهي منقسمة إلى حسنة وقبيحة.', '', '', 'L’Imâm An-Nawawi dans son livre « Tahdhîbou l-‘Asmâ-i wa l-Loughât » (tome 3 page 22 de cette édition) a dit :', 'ahlou s-sounnah, al-qawa3id, allah, aqida'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = '« البدعة بكسر الباء في الشرع هي: إحداث ما لم يكن في عهد رسول الله صلّى الله عليه وءاله وسلم، وهي منقسمة إلى حسنة وقبيحة.');

